const sub = $('Fetch Due Subscriptions').item.json;
const overageRows = $input.all().map(i => i.json);

const totalOverageCents = overageRows.reduce((sum, r) => sum + Number(r.overage_cost_cents || 0), 0);
const basePriceCents = Number(sub.base_price_cents);
const totalCents = basePriceCents + totalOverageCents;

const invoice = {
  organization_id: sub.organization_id,
  subscription_id: sub.subscription_id,
  org_name: sub.org_name,
  plan_name: sub.plan_name,
  period_start: sub.current_period_start,
  period_end: sub.current_period_end,
  base_price_cents: basePriceCents,
  overage_cents: totalOverageCents,
  total_cents: totalCents,
  overage_breakdown: overageRows.filter(r => Number(r.overage_units) > 0),
  base_display: 'R' + (basePriceCents / 100).toLocaleString('en-ZA', { minimumFractionDigits: 2 }),
  overage_display: 'R' + (totalOverageCents / 100).toLocaleString('en-ZA', { minimumFractionDigits: 2 }),
  total_display: 'R' + (totalCents / 100).toLocaleString('en-ZA', { minimumFractionDigits: 2 }),
};

return [{ json: invoice }];

